357→/**
358→ * Resolve the file path for an execute request.
359→ *
360→ * The function reference can be in "file:function" format or just a function name.
361→ * If just a name, falls back to the last analyzed file.
362→ */
363→function resolveFileForExecute(funcRef: string): string | null {
364→  if (funcRef.includes(":")) {
365→    // file:function format — extract the file part
366→    const lastColon = funcRef.lastIndexOf(":");
367→    const file = funcRef.substring(0, lastColon);
368→    if (fs.existsSync(file)) {
369→      return path.resolve(file);
370→    }
371→  }
372→
373→  // Fall back to last analyzed file (already resolved on store)
374→  return lastAnalyzedFile;
375→}
